#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use PDF::TextExtractor;

# Function to extract specific data from a PDF
sub extract_data {
    my ($pdf_file) = @_;
    my $text_extractor = PDF::TextExtractor->new($pdf_file);
    my ($text) = $text_extractor->text;

    # Regular expressions to match specific patterns
    my $date_pattern = qr/\b\d{1,2} \w+ \d{4}\b/;
    my $author_pattern = qr/\b[A-Z][a-z]+ [A-Z][a-z]+\b/;
    my $table_pattern = qr/^\s*\|.*\|.*\|.*\|/m;

    # Extract date
    if ($text =~ /$date_pattern/) {
        print "Date: $&\n";
    } else {
        print "Date not found.\n";
    }

    # Extract author
    if ($text =~ /$author_pattern/) {
        print "Author: $&\n";
    } else {
        print "Author not found.\n";
    }

    # Extract table
    if ($text =~ /$table_pattern/) {
        print "Table found:\n";
        print $&;
    } else {
        print "Table not found.\n";
    }
}

# Path to the PDF file
my $pdf_file = 'example.pdf';
extract_data($pdf_file);
```

